VALUES
  ('aboriginal-64311456-moex-00067', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '甲在河川地盜採砂石，除使用自己所有之設備外，亦使用乙所有之機具，主管機關得否沒入乙之 機具？', '["乙之機具對甲盜採砂石助益程度，如超過一定比例，得裁處沒入", "乙對甲使用其機具盜採砂石如有故意或重大過失，得裁處沒入", "因乙非行為人，依法僅能裁處罰鍰，不得沒入", "因主管機關沒入的機具，以甲所有者為限，不得沒入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00068', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '依司法實務見解，地政機關因權利人及義務人申請，依土地法及土地登記規則所為土地權利變更 登記之處分，性質上為何種處分性質？', '["形成處分", "下命處分", "確認處分", "一般處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00069', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '國家賠償法有關因公共設施設置或管理有欠缺而發生之國家賠償責任，下列敘述何者錯誤？', '["公共設施是指由行政機關管理且直接供公共或公務目的使用之設施，是否由國家設置，並非所問", "受國家委託管理公共設施之民間團體或個人，若有管理欠缺導致人民生命、身體權利受損時， 國家必須負責賠償", "對於開放之山域等自然公物已有適當警告，人民仍從事冒險或具危險性活動，即使管理有欠缺， 國家仍不負損害賠償責任", "對於使用自然公物內之設施已為適當警告或標示，人民仍從事冒險或具危險性活動，即使設置 管理有欠缺，國家仍不負損害賠償責任 40950"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00070', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '依現行法規定，下列何者非屬依法得予以資遣之人員？', '["機關裁撤時，已任職滿20年之公務人員", "機關之業務緊縮時，尚不符合法定退休條件而須裁減之人員", "現職工作不適任，經調整其他相當工作後，仍未能達到要求標準者", "現職工作不適任者且本機關已無其他工作可予調任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00071', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '關於訴願管轄，下列敘述何者正確？', '["訴願事件，無論機關層級，均以原處分機關為訴願審理機關，俾以實現行政自我審查之目的", "委任事件之訴願管轄，應將委任機關認定為原處分機關，而向該委任機關或其直接上級機關提 起訴願", "委託事件之訴願管轄，應將委託機關視為原處分機關，而向該委託機關或其直接上級機關提起 訴願", "對於公平交易委員會所作成之行政處分不服，仍可提起訴願，又為維護獨立機關之獨立功能， 由公平交易委員會自行審理訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00072', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '關於行政罰之處罰對象，下列敘述何者正確？', '["非法人團體之管理人執行職務，因重大過失致該非法人團體違反行政法上義務而應受處罰時， 應並受同一規定罰鍰之處罰", "私法人之董事與私法人應併受處罰時，得由行政機關決定僅處罰該私法人", "主管機關以行政機關為處罰對象時，須得其上級機關之許可", "違反同一行政法上義務者有多數人時，得類推適用刑法上共同正犯之規定處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00073', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '下列何者不符合行政訴訟法調解程序之規定？', '["調解程序由調解委員主持為原則，法官認為適當時，亦可由法官主持", "訴願決定送達後、行政訴訟起訴前可開始進行調解", "行政法院得依職權通知第三人參加調解", "調解事項不限於行政訴訟標的，但須經法院許可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00074', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '依行政執行法規定，關於怠金之敘述，下列何者錯誤？', '["對於可代為履行之行為義務，亦得處以怠金", "對於不行為義務，亦得處以怠金", "怠金得與罰鍰併科，並無一事不二罰原則之適用", "怠金得與罰金併科，並無一事不二罰原則之適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00075', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '關於訴願之提起，下列敘述何者正確？', '["訴願之提起，應自行政處分達到或公告期滿之日起2個月內為之", "利害關係人提起訴願者，應自知悉行政處分時起算20日內為之", "訴願之提起，以原行政處分機關或受理訴願機關收受訴願書之日期為準", "訴願人誤向原行政處分機關或受理訴願機關以外之機關提起訴願者，以該機關收受之次日，視 為提起訴願之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00076', 'aboriginal-64311456', 'aboriginal-64311456-moex-113-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '下列何者非屬基於特別犧牲所成立之補償？', '["戒嚴時期人民因內亂罪被沒收財產，於受無罪判決確定後，無法發還該財產時而為之補償", "因土地徵收而為之補償", "疫情期間徵用防疫物資而為之補償", "主管機關對於既成道路在依法徵收或價購前，因埋設地下設施物而為之補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "403", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
